# This script reads the existing aurora_language_architecture.py,
# applies a minimal, protocol-compliant patch to ExpressionEcology
# (adds telemetry facade properties and counters),
# and writes a patched file without altering any other logic.

from pathlib import Path
import re

src_path = Path("/mnt/data/aurora_language_architecture.py")
dst_path = Path("/mnt/data/aurora_language_architecture_PATCHED.py")

text = src_path.read_text()

# 1) Ensure counters exist in __init__ of ExpressionEcology
def patch_init(match):
    block = match.group(0)
    if "_spawned" in block and "_killed" in block:
        return block  # already patched
    insert = "\n        self._spawned = 0\n        self._killed = 0\n"
    return block.rstrip() + insert

text = re.sub(
    r"(class ExpressionEcology[\s\S]*?def __init__\([\s\S]*?\):[\s\S]*?\n)",
    patch_init,
    text,
    count=1
)

# 2) Add telemetry facade properties at end of ExpressionEcology class
telemetry_block = """
    # -------------------------
    # Telemetry Facade (ACE)
    # -------------------------
    @property
    def spawned(self):
        return getattr(self, "_spawned", 0)

    @property
    def killed(self):
        return getattr(self, "_killed", 0)

    @property
    def alive(self):
        return max(0, self.spawned - self.killed)

    @property
    def total(self):
        return self.spawned
"""

# Insert before the next class definition after ExpressionEcology
pattern = r"(class ExpressionEcology[\s\S]*?)(\nclass\s)"
if re.search(pattern, text):
    text = re.sub(pattern, r"\1\n" + telemetry_block + r"\2", text, count=1)
else:
    # Fallback: append at end
    text += telemetry_block

dst_path.write_text(text)

str(dst_path)

